-- ============================================================
-- EKSPORT PYTAŃ
-- Przedmiot: Mikrobiologia jamy ustnej (stoma-mikrobio-ju)
-- Temat:     Zaliczenie całościowe (MJU-ZAL)
-- Data:      2026-05-24
-- Liczba:    245
-- ============================================================

SELECT
  q.id,
  q.text AS pytanie,
  q.options,
  q.correct_option_id AS poprawna_odpowiedz,
  q.explanation AS wyjasnienie
FROM public.questions q
WHERE q.topic_id = 'MJU-ZAL'
  AND q.is_active = true
ORDER BY q.id;

